export type Cell = [number, number];

function isNeighbor(a: Cell, b: Cell): boolean {
  const rowDistance = Math.abs(a[0] - b[0]);
  const colDistance = Math.abs(a[1] - b[1]);
  const isSameCell = rowDistance === 0 && colDistance === 0;
  const isWithinOneStep = rowDistance <= 1 && colDistance <= 1;
  return !isSameCell && isWithinOneStep;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const countNeighbors = (cell: Cell): number =>
    liveCells.filter((other) => isNeighbor(other, cell)).length;

  const survivors = liveCells.filter((cell) => {
    const neighbors = countNeighbors(cell);
    return neighbors === 2 || neighbors === 3;
  });

  const isLive = (cell: Cell): boolean =>
    liveCells.some((other) => other[0] === cell[0] && other[1] === cell[1]);

  const deadNeighbors: Cell[] = [];
  for (const cell of liveCells) {
    for (let dRow = -1; dRow <= 1; dRow++) {
      for (let dCol = -1; dCol <= 1; dCol++) {
        const candidate: Cell = [cell[0] + dRow, cell[1] + dCol];
        if (
          !isLive(candidate) &&
          countNeighbors(candidate) === 3 &&
          !deadNeighbors.some(
            (d) => d[0] === candidate[0] && d[1] === candidate[1]
          )
        ) {
          deadNeighbors.push(candidate);
        }
      }
    }
  }

  return [...survivors, ...deadNeighbors];
}

